  1	import {
  2	  Button,
  3	  DataList,
  4	  DataListCell,
  5	  DataListCheck,
  6	  DataListControl,
  7	  DataListDragButton,
  8	  DataListItem,
  9	  DataListItemCells,
 10	  DataListItemRow,
 11	  DragDrop,
 12	  Draggable,
 13	  Droppable,
 14	  Flex,
 15	  FlexItem,
 16	  Text,
 17	  TextContent,
 18	  TextVariants,
 19	  Tooltip
 20	} from '@patternfly/react-core';
 21	import * as _ from 'lodash';
 22	import * as React from 'react';
 23	import { useTranslation } from 'react-i18next';
 24	import { Feature } from '../../model/config';
 25	import { RecordType } from '../../model/flow-query';
 26	import { getDefaultOverviewPanels, getOverviewPanelInfo, OverviewPanel } from '../../utils/overview-panels';
 27	import Modal from './modal';
 28	import './overview-panels-modal.css';
 29	
 30	const PANELS_DRAG_ZONE = 'netobs-overview-panels-modal';
 31	
 32	export interface OverviewPanelsModalProps {
 33	  isModalOpen: boolean;
 34	  setModalOpen: (v: boolean) => void;
 35	  recordType: RecordType;
 36	  panels: OverviewPanel[];
 37	  setPanels: (v: OverviewPanel[]) => void;
 38	  customIds?: string[];
 39	  features: Feature[];
 40	  id?: string;
 41	}
 42	
 43	export const OverviewPanelsModal: React.FC<OverviewPanelsModalProps> = ({
 44	  id,
 45	  isModalOpen,
 46	  setModalOpen,
 47	  recordType,
 48	  panels,
 49	  setPanels,
 50	  customIds,
 51	  features
 52	}) => {
 53	  const [updatedPanels, setUpdatedPanels] = React.useState<OverviewPanel[]>([]);
 54	  const [filterKeys, setFilterKeys] = React.useState<string[]>([]);
 55	  const { t } = useTranslation('plugin__netobserv-plugin');
 56	  const dragDescriptionId = 'overview-panels-drag-description';
 57	
 58	  React.useEffect(() => {
 59	    if (isModalOpen) {
 60	      setFilterKeys([]);
 61	    }
 62	  }, [isModalOpen]);
 63	
 64	  React.useEffect(() => {
 65	    if (!isModalOpen || _.isEmpty(updatedPanels)) {
 66	      setUpdatedPanels(_.cloneDeep(panels));
 67	    }
 68	    // eslint-disable-next-line react-hooks/exhaustive-deps
 69	  }, [isModalOpen, panels]);
 70	
 71	  const getFilterKeys = React.useCallback(() => {
 72	    let panelFilterKeys = ['total', 'bar', 'donut', 'line'];
 73	
 74	    if (features.includes('pktDrop')) {
 75	      panelFilterKeys.push('dropped');
 76	    }
 77	
 78	    if (features.includes('dnsTracking') || features.includes('flowRTT')) {
 79	      panelFilterKeys = panelFilterKeys.concat(['rate', 'top', 'bottom', 'min', 'avg', 'max', 'p90', 'p99']);
 80	      if (features.includes('dnsTracking')) {
 81	        panelFilterKeys.push('dns');
 82	      }
 83	      if (features.includes('flowRTT')) {
 84	        panelFilterKeys.push('rtt');
 85	      }
 86	    }
 87	
 88	    return panelFilterKeys;
 89	  }, [features]);
 90	
 91	  const isFilteredPanel = React.useCallback(
 92	    (p: OverviewPanel) => {
 93	      return (
 94	        _.isEmpty(filterKeys) ||
 95	        _.reduce(
 96	          filterKeys,
 97	          (acc, fk) => {
 98	            const panelInfo = getOverviewPanelInfo(
 99	              t,
100	              p.id,
101	              undefined,
102	              recordType === 'flowLog' ? t('flow') : t('conversation')
103	            );
104	            const str = `${p.id}: ${panelInfo.title} - ${panelInfo.chartType}`;
105	            return (acc = acc && str.toLowerCase().includes(fk));
106	          },
107	          true
108	        )
109	      );
110	    },
111	    [filterKeys, recordType, t]
112	  );
113	
114	  const onListDrop = React.useCallback(
115	    (source: { droppableId: string; index: number }, dest?: { droppableId: string; index: number }) => {
116	      if (!dest || source.droppableId !== dest.droppableId) {
117	        return false;
118	      }
119	      const oldIndex = source.index;
120	      const newIndex = dest.index;
121	      if (oldIndex === newIndex) {
122	        return false;
123	      }
124	      let accepted = false;
125	      setUpdatedPanels(prev => {
126	        const filtered = prev.filter(p => isFilteredPanel(p));
127	        if (oldIndex < 0 || oldIndex >= filtered.length || newIndex < 0 || newIndex >= filtered.length) {
128	          return prev;
129	        }
130	        const reorderedFiltered = [...filtered];
131	        const [removed] = reorderedFiltered.splice(oldIndex, 1);
132	        reorderedFiltered.splice(newIndex, 0, removed);
133	        const next: OverviewPanel[] = [];
134	        const fq = [...reorderedFiltered];
135	        for (const panel of prev) {
136	          if (isFilteredPanel(panel)) {
137	            const shifted = fq.shift();
138	            if (shifted) {
139	              next.push(shifted);
140	            }
141	          } else {
142	            next.push(panel);
143	          }
144	        }
145	        accepted = true;
146	        return next;
147	      });
148	      return accepted;
149	    },
150	    [isFilteredPanel]
151	  );
152	
153	  const onCheck = React.useCallback(
154	    // eslint-disable-next-line @typescript-eslint/no-unused-vars
155	    (event: React.FormEvent<HTMLInputElement>, checked: boolean) => {
156	      if (event?.target && 'id' in event.target) {
157	        const panelId = (event.target as HTMLInputElement).id;
158	        setUpdatedPanels(prevPanels =>
159	          prevPanels.map(panel => (panel.id === panelId ? { ...panel, isSelected: checked } : panel))
160	        );
161	      }
162	    },
163	    []
164	  );
165	
166	  const onReset = React.useCallback(() => {
167	    setUpdatedPanels(getDefaultOverviewPanels(customIds).filter(p => panels.some(existing => existing.id === p.id)));
168	  }, [customIds, panels]);
169	
170	  const isSaveDisabled = React.useCallback(() => {
171	    return _.isEmpty(updatedPanels.filter(p => p.isSelected));
172	  }, [updatedPanels]);
173	
174	  const filteredPanels = React.useCallback(() => {
175	    return updatedPanels.filter(p => isFilteredPanel(p));
176	  }, [isFilteredPanel, updatedPanels]);
177	
178	  const isAllSelected = React.useCallback(() => {
179	    return _.reduce(filteredPanels(), (acc, p) => (acc = acc && p.isSelected), true);
180	  }, [filteredPanels]);
181	
182	  const onSelectAll = React.useCallback(() => {
183	    const allSelected = isAllSelected();
184	    setUpdatedPanels(prevPanels =>
185	      prevPanels.map(panel => (isFilteredPanel(panel) ? { ...panel, isSelected: !allSelected } : panel))
186	    );
187	  }, [isAllSelected, isFilteredPanel]);
188	
189	  const onClose = React.useCallback(() => {
190	    setUpdatedPanels(_.cloneDeep(panels));
191	    setModalOpen(false);
192	  }, [panels, setModalOpen]);
193	
194	  const onSave = React.useCallback(() => {
195	    setPanels(updatedPanels);
196	    onClose();
197	  }, [setPanels, updatedPanels, onClose]);
198	
199	  const toggleChip = React.useCallback(
200	    (key: string) => {
201	      if (filterKeys.includes(key)) {
202	        setFilterKeys(filterKeys.filter(k => k !== key));
203	      } else {
204	        setFilterKeys(getFilterKeys().filter(f => f === key || filterKeys.includes(f)));
205	      }
206	    },
207	    [filterKeys, getFilterKeys]
208	  );
209	
210	  const flowOrConversation = recordType === 'flowLog' ? t('flow') : t('conversation');
211	
212	  return (
213	    <Modal
214	      id={id}
215	      title={t('Manage panels')}
216	      isOpen={isModalOpen}
217	      scrollable={true}
218	      onClose={() => onClose()}
219	      description={
220	        <>
221	          <TextContent>
222	            <Text component={TextVariants.p}>
223	              {t('Selected panels will appear in the overview tab.')}&nbsp;
224	              {t('Click and drag the items to reorder the panels in the overview tab.')}
225	            </Text>
226	          </TextContent>
227	          <Flex className="popup-header-margin">
228	            <FlexItem flex={{ default: 'flex_4' }}>
229	              <Flex className="flex-gap">
230	                {getFilterKeys().map(key => {
231	                  return (
232	                    <FlexItem
233	                      key={key}
234	                      onClick={() => toggleChip(key)}
235	                      className={`custom-chip ${
236	                        filterKeys.includes(key) ? 'selected' : 'unselected'
237	                      } buttonless gap pointer`}
238	                    >
239	                      <Text component={TextVariants.p}>{key}</Text>
240	                    </FlexItem>
241	                  );
242	                })}
243	              </Flex>
244	            </FlexItem>
245	            <FlexItem flex={{ default: 'flex_1' }} className="flex-center">
246	              {_.isEmpty(filteredPanels()) ? (
247	                <Button isInline onClick={() => setFilterKeys([])} variant="link">
248	                  {t('Clear filters')}
249	                </Button>
250	              ) : (
251	                <Button isInline onClick={onSelectAll} variant="link">
252	                  {`${isAllSelected() ? t('Unselect all') : t('Select all')}${
253	                    !_.isEmpty(filterKeys) ? ' ' + filterKeys.join(',') : ''
254	                  }`}
255	                </Button>
256	              )}
257	            </FlexItem>
258	          </Flex>
259	        </>
260	      }
261	      footer={
262	        <>
263	          <Button data-test="panels-reset-button" key="reset" variant="link" onClick={() => onReset()}>
264	            {t('Restore default panels')}
265	          </Button>
266	          <Button data-test="panels-cancel-button" key="cancel" variant="link" onClick={() => onClose()}>
267	            {t('Cancel')}
268	          </Button>
269	          <Tooltip content={t('At least one panel must be selected')} isVisible={isSaveDisabled()}>
270	            <Button
271	              data-test="panels-save-button"
272	              isDisabled={isSaveDisabled()}
273	              key="confirm"
274	              variant="primary"
275	              onClick={() => onSave()}
276	            >
277	              {t('Save')}
278	            </Button>
279	          </Tooltip>
280	        </>
281	      }
282	    >
283	      <div className="co-m-form-row" id="drag-drop-container-overview">
284	        <DragDrop onDrop={onListDrop}>
285	          <Droppable hasNoWrapper zone={PANELS_DRAG_ZONE} droppableId="overview-panels-list">
286	            <DataList
287	              aria-label="Overview panel management"
288	              data-test="overview-panel-management"
289	              id="overview-panel-management"
290	              isCompact
291	            >
292	              {filteredPanels().map(panel => {
293	                const info = getOverviewPanelInfo(t, panel.id, undefined, flowOrConversation);
294	                const rowLabelId = `overview-panel-management-item-${panel.id}`;
295	                return (
296	                  <Draggable key={panel.id} hasNoWrapper>
297	                    <DataListItem aria-labelledby={rowLabelId} id={`overview-panel-management-row-${panel.id}`}>
298	                      <DataListItemRow>
299	                        <DataListControl className="netobserv-data-list-control">
300	                          <DataListDragButton
301	                            aria-label={t('Reorder panel')}
302	                            aria-labelledby={rowLabelId}
303	                            aria-describedby={dragDescriptionId}
304	                            aria-pressed={false}
305	                          />
306	                          <DataListCheck
307	                            aria-labelledby={rowLabelId}
308	                            isChecked={panel.isSelected}
309	                            id={panel.id}
310	                            onChange={onCheck}
311	                            otherControls
312	                          />
313	                        </DataListControl>
314	                        <DataListItemCells
315	                          dataListCells={[
316	                            <DataListCell key={`data-list-cell-${panel.id}`}>
317	                              <label htmlFor={panel.id} id={rowLabelId}>
318	                                {info.title}
319	                                {info.chartType && <>{' (' + info.chartType + ')'}</>}
320	                              </label>
321	                            </DataListCell>
322	                          ]}
323	                        />
324	                      </DataListItemRow>
325	                    </DataListItem>
326	                  </Draggable>
327	                );
328	              })}
329	            </DataList>
330	          </Droppable>
331	          <div className="pf-v6-screen-reader" id={dragDescriptionId}>
332	            {t(
333	              // eslint-disable-next-line max-len
334	              'Press space or enter to begin dragging, and use the arrow keys to navigate up or down. Press enter to confirm the drag, or any other key to cancel the drag operation.'
335	            )}
336	          </div>
337	        </DragDrop>
338	      </div>
339	    </Modal>
340	  );
341	};
342	
343	export default OverviewPanelsModal;

