305	                          />
306	                          <DataListCheck
307	                            aria-labelledby={rowLabelId}
308	                            isChecked={panel.isSelected}
309	                            id={panel.id}
310	                            onChange={onCheck}
311	                            otherControls
312	                          />
313	                        </DataListControl>
314	                        <DataListItemCells
315	                          dataListCells={[
316	                            <DataListCell key={`data-list-cell-${panel.id}`}>
317	                              <label htmlFor={panel.id} id={rowLabelId}>
318	                                {info.title}
319	                                {info.chartType && <>{' (' + info.chartType + ')'}</>}
320	                              </label>
321	                            </DataListCell>
322	                          ]}
323	                        />
324	                      </DataListItemRow>
325	                    </DataListItem>
326	                  </Draggable>
327	                );
328	              })}
329	            </DataList>
330	          </Droppable>
331	          <div className="pf-v6-screen-reader" id={dragDescriptionId}>
332	            {t(
333	              // eslint-disable-next-line max-len
334	              'Press space or enter to begin dragging, and use the arrow keys to navigate up or down. Press enter to confirm the drag, or any other key to cancel the drag operation.'
335	            )}
336	          </div>
337	        </DragDrop>
338	      </div>
339	    </Modal>
340	  );
341	};
342	
343	export default OverviewPanelsModal;

