 1	import { Button, Content, ContentVariants } from '@patternfly/react-core';
 2	import { CloseIcon } from '@patternfly/react-icons';
 3	import React from 'react';
 4	import Modal from 'react-modal';
 5	import { useTheme } from '../../utils/theme-hook';
 6	import './modal.css';
 7	
 8	export interface CustomModalProps {
 9	  title: string;
10	  description?: JSX.Element;
11	  footer?: JSX.Element;
12	  onClose?: () => void;
13	  isOpen: boolean;
14	  scrollable?: boolean;
15	  id?: string;
16	}
17	
18	const CustomModal: React.FC<CustomModalProps> = ({
19	  id,
20	  scrollable = true,
21	  isOpen,
22	  onClose,
23	  title,
24	  description,
25	  children,
26	  footer
27	}) => {
28	  const isDarkTheme = useTheme();
29	
30	  return isOpen ? (
31	    <Modal
32	      data-test={id}
33	      id={id}
34	      isOpen={isOpen}
35	      className={'modal-dialog'}
36	      ariaHideApp={false}
37	      onRequestClose={() => (onClose ? onClose() : console.error('modal called onClose but is undefined'))}
38	      overlayClassName="co-overlay"
39	    >
40	      <div className={`modal-content modal-content--no-inner-scroll ${isDarkTheme ? 'dark' : 'light'}`}>
41	        <div data-test={`${id}-header`} className="modal-header">
42	          <Content component={ContentVariants.h1}>
43	            {title}
44	            {onClose && (
45	              <Button
46	                data-test={`${id}-close-button`}
47	                className={'co-close-button co-close-button--float-right'}
48	                onClick={e => {
49	                  e.stopPropagation();
50	                  onClose();
51	                }}
52	                variant="plain"
53	                icon={<CloseIcon />}
54	              />
55	            )}
56	          </Content>
57	          {description && <div className="modal-description">{description}</div>}
58	        </div>
59	        {children && (
60	          <div data-test={`${id}-body`} className={`${'modal-body'} ${scrollable ? 'scrollable' : 'overflow-visible'}`}>
61	            {children}
62	          </div>
63	        )}
64	        {footer && (
65	          <div data-test={`${id}-footer`} className="modal-footer">
66	            {footer}
67	          </div>
68	        )}
69	      </div>
70	    </Modal>
71	  ) : (
72	    <></>
73	  );
74	};
75	
76	export default CustomModal;

