  1	import {
  2	  Button,
  3	  Content,
  4	  ContentVariants,
  5	  DataList,
  6	  DataListCell,
  7	  DataListCheck,
  8	  DataListControl,
  9	  DataListDragButton,
 10	  DataListItem,
 11	  DataListItemCells,
 12	  DataListItemRow,
 13	  DragDrop,
 14	  Draggable,
 15	  Droppable,
 16	  Flex,
 17	  FlexItem,
 18	  Tooltip
 19	} from '@patternfly/react-core';
 20	import * as _ from 'lodash';
 21	import * as React from 'react';
 22	import { useTranslation } from 'react-i18next';
 23	import { Feature } from '../../model/config';
 24	import { RecordType } from '../../model/flow-query';
 25	import { getDefaultOverviewPanels, getOverviewPanelInfo, OverviewPanel } from '../../utils/overview-panels';
 26	import Modal from './modal';
 27	import './overview-panels-modal.css';
 28	
 29	const PANELS_DRAG_ZONE = 'netobs-overview-panels-modal';
 30	
 31	export interface OverviewPanelsModalProps {
 32	  isModalOpen: boolean;
 33	  setModalOpen: (v: boolean) => void;
 34	  recordType: RecordType;
 35	  panels: OverviewPanel[];
 36	  setPanels: (v: OverviewPanel[]) => void;
 37	  customIds?: string[];
 38	  features: Feature[];
 39	  id?: string;
 40	}
 41	
 42	export const OverviewPanelsModal: React.FC<OverviewPanelsModalProps> = ({
 43	  id,
 44	  isModalOpen,
 45	  setModalOpen,
 46	  recordType,
 47	  panels,
 48	  setPanels,
 49	  customIds,
 50	  features
 51	}) => {
 52	  const [updatedPanels, setUpdatedPanels] = React.useState<OverviewPanel[]>([]);
 53	  const [filterKeys, setFilterKeys] = React.useState<string[]>([]);
 54	  const { t } = useTranslation('plugin__netobserv-plugin');
 55	  const dragDescriptionId = 'overview-panels-drag-description';
 56	
 57	  React.useEffect(() => {
 58	    if (isModalOpen) {
 59	      setFilterKeys([]);
 60	    }
 61	  }, [isModalOpen]);
 62	
 63	  React.useEffect(() => {
 64	    if (!isModalOpen || _.isEmpty(updatedPanels)) {
 65	      setUpdatedPanels(_.cloneDeep(panels));
 66	    }
 67	    // eslint-disable-next-line react-hooks/exhaustive-deps
 68	  }, [isModalOpen, panels]);
 69	
 70	  const getFilterKeys = React.useCallback(() => {
 71	    let panelFilterKeys = ['total', 'bar', 'donut', 'line'];
 72	
 73	    if (features.includes('pktDrop')) {
 74	      panelFilterKeys.push('dropped');
 75	    }
 76	
 77	    if (features.includes('dnsTracking') || features.includes('flowRTT')) {
 78	      panelFilterKeys = panelFilterKeys.concat(['rate', 'top', 'bottom', 'min', 'avg', 'max', 'p90', 'p99']);
 79	      if (features.includes('dnsTracking')) {
 80	        panelFilterKeys.push('dns');
 81	      }
 82	      if (features.includes('flowRTT')) {
 83	        panelFilterKeys.push('rtt');
 84	      }
 85	    }
 86	
 87	    return panelFilterKeys;
 88	  }, [features]);
 89	
 90	  const isFilteredPanel = React.useCallback(
 91	    (p: OverviewPanel) => {
 92	      return (
 93	        _.isEmpty(filterKeys) ||
 94	        _.reduce(
 95	          filterKeys,
 96	          (acc, fk) => {
 97	            const panelInfo = getOverviewPanelInfo(
 98	              t,
 99	              p.id,
100	              undefined,
101	              recordType === 'flowLog' ? t('flow') : t('conversation')
102	            );
103	            const str = `${p.id}: ${panelInfo.title} - ${panelInfo.chartType}`;
104	            return (acc = acc && str.toLowerCase().includes(fk));
105	          },
106	          true
107	        )
108	      );
109	    },
110	    [filterKeys, recordType, t]
111	  );
112	
113	  const onListDrop = React.useCallback(
114	    (source: { droppableId: string; index: number }, dest?: { droppableId: string; index: number }) => {
115	      if (!dest || source.droppableId !== dest.droppableId) {
116	        return false;
117	      }
118	      const oldIndex = source.index;
119	      const newIndex = dest.index;
120	      if (oldIndex === newIndex) {
121	        return false;
122	      }
123	      let accepted = false;
124	      setUpdatedPanels(prev => {
125	        const filtered = prev.filter(p => isFilteredPanel(p));
126	        if (oldIndex < 0 || oldIndex >= filtered.length || newIndex < 0 || newIndex >= filtered.length) {
127	          return prev;
128	        }
129	        const reorderedFiltered = [...filtered];
130	        const [removed] = reorderedFiltered.splice(oldIndex, 1);
131	        reorderedFiltered.splice(newIndex, 0, removed);
132	        const next: OverviewPanel[] = [];
133	        const fq = [...reorderedFiltered];
134	        for (const panel of prev) {
135	          if (isFilteredPanel(panel)) {
136	            const shifted = fq.shift();
137	            if (shifted) {
138	              next.push(shifted);
139	            }
140	          } else {
141	            next.push(panel);
142	          }
143	        }
144	        accepted = true;
145	        return next;
146	      });
147	      return accepted;
148	    },
149	    [isFilteredPanel]
150	  );
151	
152	  const onCheck = React.useCallback(
153	    // eslint-disable-next-line @typescript-eslint/no-unused-vars
154	    (event: React.FormEvent<HTMLInputElement>, checked: boolean) => {
155	      if (event?.target && 'id' in event.target) {
156	        const panelId = (event.target as HTMLInputElement).id;
157	        setUpdatedPanels(prevPanels =>
158	          prevPanels.map(panel => (panel.id === panelId ? { ...panel, isSelected: checked } : panel))
159	        );
160	      }
161	    },
162	    []
163	  );
164	
165	  const onReset = React.useCallback(() => {
166	    setUpdatedPanels(getDefaultOverviewPanels(customIds).filter(p => panels.some(existing => existing.id === p.id)));
167	  }, [customIds, panels]);
168	
169	  const isSaveDisabled = React.useCallback(() => {
170	    return _.isEmpty(updatedPanels.filter(p => p.isSelected));
171	  }, [updatedPanels]);
172	
173	  const filteredPanels = React.useCallback(() => {
174	    return updatedPanels.filter(p => isFilteredPanel(p));
175	  }, [isFilteredPanel, updatedPanels]);
176	
177	  const isAllSelected = React.useCallback(() => {
178	    return _.reduce(filteredPanels(), (acc, p) => (acc = acc && p.isSelected), true);
179	  }, [filteredPanels]);
180	
181	  const onSelectAll = React.useCallback(() => {
182	    const allSelected = isAllSelected();
183	    setUpdatedPanels(prevPanels =>
184	      prevPanels.map(panel => (isFilteredPanel(panel) ? { ...panel, isSelected: !allSelected } : panel))
185	    );
186	  }, [isAllSelected, isFilteredPanel]);
187	
188	  const onClose = React.useCallback(() => {
189	    setUpdatedPanels(_.cloneDeep(panels));
190	    setModalOpen(false);
191	  }, [panels, setModalOpen]);
192	
193	  const onSave = React.useCallback(() => {
194	    setPanels(updatedPanels);
195	    onClose();
196	  }, [setPanels, updatedPanels, onClose]);
197	
198	  const toggleChip = React.useCallback(
199	    (key: string) => {
200	      if (filterKeys.includes(key)) {
201	        setFilterKeys(filterKeys.filter(k => k !== key));
202	      } else {
203	        setFilterKeys(getFilterKeys().filter(f => f === key || filterKeys.includes(f)));
204	      }
205	    },
206	    [filterKeys, getFilterKeys]
207	  );
208	
209	  const flowOrConversation = recordType === 'flowLog' ? t('flow') : t('conversation');
210	
211	  return (
212	    <Modal
213	      id={id}
214	      title={t('Manage panels')}
215	      isOpen={isModalOpen}
216	      scrollable={true}
217	      onClose={() => onClose()}
218	      description={
219	        <>
220	          <Content>
221	            <Content component={ContentVariants.p}>
222	              {t('Selected panels will appear in the overview tab.')}&nbsp;
223	              {t('Click and drag the items to reorder the panels in the overview tab.')}
224	            </Content>
225	          </Content>
226	          <Flex className="popup-header-margin">
227	            <FlexItem flex={{ default: 'flex_4' }}>
228	              <Flex className="flex-gap">
229	                {getFilterKeys().map(key => {
230	                  return (
231	                    <FlexItem
232	                      key={key}
233	                      onClick={() => toggleChip(key)}
234	                      className={`custom-chip ${
235	                        filterKeys.includes(key) ? 'selected' : 'unselected'
236	                      } buttonless gap pointer`}
237	                    >
238	                      <Content component={ContentVariants.p}>{key}</Content>
239	                    </FlexItem>
240	                  );
241	                })}
242	              </Flex>
243	            </FlexItem>
244	            <FlexItem flex={{ default: 'flex_1' }} className="flex-center">
245	              {_.isEmpty(filteredPanels()) ? (
246	                <Button isInline onClick={() => setFilterKeys([])} variant="link">
247	                  {t('Clear filters')}
248	                </Button>
249	              ) : (
250	                <Button isInline onClick={onSelectAll} variant="link">
251	                  {`${isAllSelected() ? t('Unselect all') : t('Select all')}${
252	                    !_.isEmpty(filterKeys) ? ' ' + filterKeys.join(',') : ''
253	                  }`}
254	                </Button>
255	              )}
256	            </FlexItem>
257	          </Flex>
258	        </>
259	      }
260	      footer={
261	        <>
262	          <Button data-test="panels-reset-button" key="reset" variant="link" onClick={() => onReset()}>
263	            {t('Restore default panels')}
264	          </Button>
265	          <Button data-test="panels-cancel-button" key="cancel" variant="link" onClick={() => onClose()}>
266	            {t('Cancel')}
267	          </Button>
268	          <Tooltip content={t('At least one panel must be selected')} isVisible={isSaveDisabled()}>
269	            <Button
270	              data-test="panels-save-button"
271	              isDisabled={isSaveDisabled()}
272	              key="confirm"
273	              variant="primary"
274	              onClick={() => onSave()}
275	            >
276	              {t('Save')}
277	            </Button>
278	          </Tooltip>
279	        </>
280	      }
281	    >
282	      <div className="co-m-form-row" id="drag-drop-container-overview">
283	        <DragDrop onDrop={onListDrop}>
284	          <Droppable hasNoWrapper zone={PANELS_DRAG_ZONE} droppableId="overview-panels-list">
285	            <DataList
286	              aria-label="Overview panel management"
287	              data-test="overview-panel-management"
288	              id="overview-panel-management"
289	              isCompact
290	            >
291	              {filteredPanels().map(panel => {
292	                const info = getOverviewPanelInfo(t, panel.id, undefined, flowOrConversation);
293	                const rowLabelId = `overview-panel-management-item-${panel.id}`;
294	                return (
295	                  <Draggable key={panel.id} hasNoWrapper>
296	                    <DataListItem aria-labelledby={rowLabelId} id={`overview-panel-management-row-${panel.id}`}>
297	                      <DataListItemRow>
298	                        <DataListControl className="netobserv-data-list-control">
299	                          <DataListDragButton
300	                            aria-label={t('Reorder panel')}
301	                            aria-labelledby={rowLabelId}
302	                            aria-describedby={dragDescriptionId}
303	                            aria-pressed={false}
304	                          />
305	                          <DataListCheck
306	                            aria-labelledby={rowLabelId}
307	                            isChecked={panel.isSelected}
308	                            id={panel.id}
309	                            onChange={onCheck}
310	                            otherControls
311	                          />
312	                        </DataListControl>
313	                        <DataListItemCells
314	                          dataListCells={[
315	                            <DataListCell key={`data-list-cell-${panel.id}`}>
316	                              <label htmlFor={panel.id} id={rowLabelId}>
317	                                {info.title}
318	                                {info.chartType && <>{' (' + info.chartType + ')'}</>}
319	                              </label>
320	                            </DataListCell>
321	                          ]}
322	                        />
323	                      </DataListItemRow>
324	                    </DataListItem>
325	                  </Draggable>
326	                );
327	              })}
328	            </DataList>
329	          </Droppable>
330	          <div className="pf-v6-screen-reader" id={dragDescriptionId}>
331	            {t(
332	              // eslint-disable-next-line max-len
333	              'Press space or enter to begin dragging, and use the arrow keys to navigate up or down. Press enter to confirm the drag, or any other key to cancel the drag operation.'
334	            )}
335	          </div>
336	        </DragDrop>
337	      </div>
338	    </Modal>
339	  );
340	};
341	
342	export default OverviewPanelsModal;

